export function getV8SettingsBoardStats() {
  const dangerCount = settingsBoardStates.filter((state) => ["review", "confirming"].includes(state.lifecycleStatus)).length;
  const failureCount = settingsBoardStates.filter((state) => state.lifecycleStatus === "failed").length;

  return {
    flowCount: settingsBoardFlows.length,
    stateCount: settingsBoardStates.length,
    dangerCount,
    failureCount,
    homeCount: settingsBoardStates.filter((state) => state.phone.kind === "home").length,
  };
}
